import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.println("Enter a string:");
        String input = scanner.nextLine(); // Read the entire line

        char[] buffer = new char[10];

        if (input.length() <= buffer.length) {
            input.getChars(0, input.length(), buffer, 0); // Copy only up to buffer length
        } else {
            input.getChars(0, buffer.length, buffer, 0); // Truncate to fit within buffer size
        }

        System.out.println("Buffer content: " + new String(buffer));

        scanner.close();
    }
}

### Explanation:
취약유형: Buffer Overflow
